const rows = $input.all().map(r => r.json);
const thisWeek = rows.filter(r => r.period === 'this' && r.referrer_domain !== 'no-ai-traffic');
const prevWeek = rows.filter(r => r.period === 'prev' && r.referrer_domain !== 'no-ai-traffic');

const bySource = {};
for (const r of thisWeek) bySource[r.referrer_domain] = (bySource[r.referrer_domain]||0) + parseInt(r.sessions);
const prevTotal = prevWeek.reduce((s,r) => s+parseInt(r.sessions), 0);
const thisTotal = Object.values(bySource).reduce((a,b)=>a+b, 0);
const trend = prevTotal > 0 ? Math.round((thisTotal-prevTotal)/prevTotal*100) : null;

const bySite = {};
for (const r of thisWeek) {
  if (!bySite[r.domain]) bySite[r.domain] = 0;
  bySite[r.domain] += parseInt(r.sessions);
}

const icons = {'perplexity.ai':'🔮','chatgpt.com':'🤖','claude.ai':'🧠','bing.com':'🔵'};
const sourceLines = Object.entries(bySource).sort((a,b)=>b[1]-a[1])
  .map(([s,n]) => (icons[s]||'•')+' '+s+': '+n).join('\n');
const siteLines = Object.entries(bySite).map(([d,n]) => '  '+d.replace('.com','')+': '+n).join('\n');
const trendStr = trend===null ? 'forsta matningen' : (trend>0?'+':'')+trend+'% vs fg vecka';

const text = '<b>AI-trafik – daglig rapport</b>\n\n' +
  'Denna vecka: <b>'+thisTotal+' sessioner</b>\n' +
  'Trend: '+trendStr+'\n\n' +
  '<b>Per AI-kanal:</b>\n<code>'+(sourceLines||'Ingen AI-trafik')+'</code>\n\n' +
  '<b>Per sajt:</b>\n<code>'+(siteLines||'Ingen data')+'</code>';

return [{ json: { text, thisTotal, bySource } }];

